package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.KengetalMapper;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.AllArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.util.List;
import java.util.Optional;

@Slf4j
@AllArgsConstructor
public class RekenRszConstantService {

    private final RszConstantService rszConstantService;
    private final RegulManager regulManager;

    public RszConstant getRszConstantChecked(SleutelGegevens gegevens, LocalDate zoekDatum, DmfapplWnkengetal werknemersKengetalBijdrage, int typeBijdrage) {
        RszConstant constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                gegevens.getWerkgeversCategorie(), werknemersKengetalBijdrage, typeBijdrage, zoekDatum);
        checkRszConstantGevonden(constante, gegevens, werknemersKengetalBijdrage, typeBijdrage, zoekDatum);
        return constante;
    }

    public RszConstant getRszConstantChecked(
            SleutelGegevens gegevens, LocalDate zoekDatum, DmfapplWnkengetal werknemersKengetalBijdrage, WerkgeversCategorie werkgeversCategorie) {
        RszConstant constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalEnDatum(werkgeversCategorie, werknemersKengetalBijdrage, zoekDatum);

        checkRszConstantGevonden(constante, gegevens, werknemersKengetalBijdrage, 0, zoekDatum);
        return constante;
    }

    public void checkRszConstantGevonden(
            RszConstant constante, SleutelGegevens gegevens, DmfapplWnkengetal werknemersKengetalBijdrage, Integer typeBijdrage, LocalDate zoekDatum) {
        if (constante == null) {
            WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
            String opmerking = "Geen constante gevonden voor categorie: " + werkgeversCategorie + " (" + werkgeversCategorie.getCode() +
                    "), werknemersKengetalBijdrage " + werknemersKengetalBijdrage + " (" + werknemersKengetalBijdrage.getCode() +
                    "), typeBijdrage: " + typeBijdrage + " en zoekdatum: " + zoekDatum;
            log.debug(opmerking);
            regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.RSZ_CONSTANTEN_NIET_GEVONDEN, opmerking);
        }
    }

    public RszConstant getRszConstantPatronaleBijdrageErkentelijkheidsPremie(SleutelGegevens gegevens, LocalDate zoekDatum, KengetalMapper werknemersKengetalMapper) {
        RszConstant constante = null;
        List<DmfapplWnkengetal> patronaleBijdrageErkentelijkheidspremieLijst = werknemersKengetalMapper.getPatronaleBijdrageErkentelijkheidspremieLijst();
        List<RszConstant> lijst = rszConstantService.findByWerkgeversCategorieWerknemersKengetalBijdragen(
                gegevens.getWerkgeversCategorie(), patronaleBijdrageErkentelijkheidspremieLijst, zoekDatum);

        StringBuilder logTekst = new StringBuilder(" categorie: " + gegevens.getWerkgeversCategorie() + ", werknemersKengetalBijdrages (");
        for (DmfapplWnkengetal kengetal : patronaleBijdrageErkentelijkheidspremieLijst) {
            logTekst.append(", ").append(kengetal.getCode());
        }
        logTekst.append(") en zoekdatum").append(zoekDatum);

        if (lijst.size() == 1) {
            constante = lijst.get(0);
        } else {
            if (lijst.size() > 1) {
                log.info("Meerdere constanten voldoen aan findByWerkgeversCategorieWerknemersKengetalBijdragen {}", logTekst);
            }
        }
        if (constante == null) {
            log.info("Geen constante gevonden voor{}", logTekst);
        }

        checkRszConstantGevonden(constante, gegevens, patronaleBijdrageErkentelijkheidspremieLijst.get(0), 0, zoekDatum);
        return constante;
    }

    public RszConstant getRszConstantPensioenBijdrage(SleutelGegevens gegevens, LocalDate zoekDatum, KengetalMapper werknemersKengetalMapper) {
        List<RszConstant> lijst = rszConstantService.findByWerkgeversCategorieWerknemersKengetalBijdragen(
                gegevens.getWerkgeversCategorie(), werknemersKengetalMapper.getPensioenBijdragenLijst(), zoekDatum);
        return getFirstRszConstantFromList(lijst).orElse(null);
    }

    public static Optional<RszConstant> getFirstRszConstantFromList(List<RszConstant> lijst) {
        if (lijst != null && !lijst.isEmpty()) {
            return Optional.ofNullable(lijst.get(0));
        } else {
            return Optional.empty();
        }
    }
}
